@keyframes popup {
  0% { opacity: 0; transform: scale(0.8) translateY(-20px);}
  50% { opacity: 1; transform: scale(1.05) translateY(0);}
  100% { opacity: 1; transform: scale(1) translateY(0);}
}
.animate-popup {
  animation: popup 0.5s cubic-bezier(0.4,0,0.2,1);
}
*/
